import { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import Header from "../components/Header";
// import basiclogo1 from "../assets/basiclogo1.png"; // No longer needed

const LANGUAGES = [
  { code: "en", name: "English" },
  { code: "hi", name: "Hindi (हिंदी)" },
  { code: "hinglish", name: "Hinglish" },
];

const MOCK_TRANSLATIONS = {
  en: {
    title: "Detailed Analysis",
    question: "Question",
    yourAnswer: "Your Answer",
    correctAnswer: "Correct Answer",
    explanation: "Explanation",
    generatedExplanation: (correct) => `The correct answer is ${correct}. This is the most appropriate choice based on standard principles.`
  },
  hi: {
    title: "विस्तृत विश्लेषण",
    question: "प्रश्न",
    yourAnswer: "आपका उत्तर",
    correctAnswer: "सही उत्तर",
    explanation: "व्याख्या",
    generatedExplanation: (correct) => `सही उत्तर ${correct} है। मानक सिद्धांतों के आधार पर यह सबसे उपयुक्त विकल्प है।`
  },
  hinglish: {
    title: "Detailed Analysis",
    question: "Question",
    yourAnswer: "Aapka Answer",
    correctAnswer: "Sahi Answer",
    explanation: "Explanation",
    generatedExplanation: (correct) => `Sahi answer ${correct} hai. Standard principles ke hisaab se ye sabse best choice hai.`
  }
};

export default function ReportPage() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [selectedLang, setSelectedLang] = useState("en");

  if (!state?.reportUrl) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-white">
        No report found
      </div>
    );
  }

  const { reportUrl, questions, answers } = state;
  const t = MOCK_TRANSLATIONS[selectedLang];

  return (
    <div className="min-h-screen font-sans text-slate-900 dark:text-white bg-[#0B1120] flex flex-col justify-between overflow-x-hidden">
      <Header isLanding={true} />

      <div className="flex-grow w-full flex flex-col items-center justify-center relative px-4 py-8">
          {/* Global Background Effects */}
          <div className="absolute inset-0 -z-10 h-full w-full bg-[#0B1120] overflow-hidden pointer-events-none">
              <div className="absolute inset-0 bg-gradient-to-tr from-[#0B1120] via-[#1a2c55] to-[#0B1120] opacity-80"></div>
              <div className="absolute bottom-0 right-0 h-[500px] w-[500px] bg-indigo-600/20 blur-[100px] rounded-full mix-blend-screen"></div>
          </div>

        {/* CARD */}
        <AnimatePresence mode="wait">
        {!showAdvanced ? (
        <motion.div
            key="main-card"
            initial={{ x: 50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -50, opacity: 0 }}
            transition={{ type: "spring", stiffness: 100, damping: 20 }}
            className="bg-slate-900 rounded-3xl p-6 md:p-10 max-w-md w-full text-center shadow-2xl z-10"
        >
            <h1 className="text-3xl font-extrabold mb-4 text-indigo-400">
            Assessment Completed 🎉
            </h1>

            <p className="text-gray-300 mb-8">
            Your career report is ready.
            </p>

            <a
            href={reportUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="relative overflow-hidden group block w-full py-4 mb-4 rounded-xl bg-gradient-to-r from-green-600 to-emerald-600 font-bold text-white shadow-lg hover:shadow-xl transition-all"
            >
            <span className="absolute inset-0 bg-white transition-transform duration-[250ms] ease-out scale-x-0 group-hover:scale-x-100 origin-right group-hover:origin-left"></span>
            <span className="relative z-10 flex items-center justify-center gap-2 group-hover:text-green-800 transition-colors duration-300">
                📄 Download PDF Report
            </span>
            </a>

            {questions && answers && (
              <button
                onClick={() => setShowAdvanced(true)}
                className="relative overflow-hidden group w-full py-4 mb-4 rounded-xl bg-gradient-to-r from-purple-600 to-indigo-600 font-bold text-white shadow-lg hover:shadow-xl transition-all"
              >
                <span className="absolute inset-0 bg-white transition-transform duration-[250ms] ease-out scale-x-0 group-hover:scale-x-100 origin-right group-hover:origin-left"></span>
                <span className="relative z-10 flex items-center justify-center gap-2 group-hover:text-purple-800 transition-colors duration-300">
                   🔍 Advanced Analysis
                </span>
              </button>
            )}

            <button
            onClick={() => navigate("/")}
            className="relative overflow-hidden group w-full py-4 rounded-xl bg-gradient-to-r from-[#007ACC] to-[#47B5FF] font-bold text-white shadow-lg hover:shadow-xl transition-all"
            >
            <span className="absolute inset-0 bg-white transition-transform duration-[250ms] ease-out scale-x-0 group-hover:scale-x-100 origin-right group-hover:origin-left"></span>
            <span className="relative z-10 flex items-center justify-center gap-2 group-hover:text-[#002D62] transition-colors duration-300">
                🔁 Take Assessment Again
            </span>
            </button>
        </motion.div>
        ) : (
          <motion.div
            key="advanced-card"
            initial={{ x: 50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -50, opacity: 0 }}
            transition={{ type: "spring", stiffness: 100, damping: 20 }}
            className="bg-slate-900 rounded-3xl p-6 md:p-8 max-w-4xl w-full shadow-2xl z-10"
          >
            <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
              <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                <span onClick={() => setShowAdvanced(false)} className="cursor-pointer hover:text-indigo-400 transition-colors">←</span>
                {t.title}
              </h2>

              <div className="flex gap-2">
                {LANGUAGES.map(lang => (
                  <button
                    key={lang.code}
                    onClick={() => setSelectedLang(lang.code)}
                    className={`px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                      selectedLang === lang.code 
                        ? "bg-indigo-500 text-white" 
                        : "bg-slate-800 text-slate-400 hover:bg-slate-700"
                    }`}
                  >
                    {lang.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
              {questions.map((q, idx) => {
                const userAnswerIdx = answers[q.id];
                const userAnswer = q.options[userAnswerIdx];
                const correctAnswer = q.type === "mcq" ? q.options[q.correctOption] : null;

                // For preference/scenario questions, there is no single "correct" answer in the traditional sense,
                // but we can show the selected option as the user's choice.
                // If it's MCQ, we show correct answer.

                const isCorrect = q.type === "mcq" ? userAnswerIdx === q.correctOption : true;
                const displayCorrect = q.type === "mcq" ? (typeof correctAnswer === 'string' ? correctAnswer : correctAnswer.label) : "N/A - Preference Based";
                const displayUser = typeof userAnswer === 'string' ? userAnswer : userAnswer?.label;

                return (
                  <div key={q.id} className="bg-slate-800/50 rounded-xl p-4 border border-slate-700">
                    <div className="flex justify-between items-start gap-4 mb-2">
                      <h3 className="text-lg font-medium text-white">
                        <span className="text-indigo-400 mr-2">Q{idx + 1}.</span>
                        {q.text}
                      </h3>
                      <span className={`px-2 py-0.5 rounded text-xs font-bold ${isCorrect ? "bg-green-500/10 text-green-400" : "bg-red-500/10 text-red-400"}`}>
                        {q.type === "mcq" ? (isCorrect ? "Correct" : "Incorrect") : "Recorded"}
                      </span>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-3 text-sm">
                      <div className="bg-slate-900/50 p-3 rounded-lg">
                        <span className="block text-slate-500 text-xs mb-1">{t.yourAnswer}</span>
                        <span className="text-slate-200 font-medium">{displayUser}</span>
                      </div>
                      {q.type === "mcq" && (
                        <div className="bg-slate-900/50 p-3 rounded-lg">
                           <span className="block text-slate-500 text-xs mb-1">{t.correctAnswer}</span>
                           <span className="text-green-400 font-medium">{displayCorrect}</span>
                        </div>
                      )}
                    </div>

                    <div className="bg-indigo-500/5 p-3 rounded-lg border border-indigo-500/10">
                      <span className="block text-indigo-300 text-xs mb-1 font-bold uppercase tracking-wider">{t.explanation}</span>
                      <p className="text-slate-300 text-sm leading-relaxed">
                        {q.type === "mcq" 
                          ? t.generatedExplanation(displayCorrect)
                          : "This question assesses your natural preferences and tendencies. There are no right or wrong answers, only honest reflections of your personality."}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          </motion.div>
        )}
        </AnimatePresence>
      </div>

       <footer className="w-full py-4 text-center text-gray-500 text-xs bg-[#0B1120] border-t border-white/5 mt-auto relative z-10">
          <p>Copyright © 2026 All Rights Reserved. | Designed by CRZ Academic Review Pvt Ltd.</p>
       </footer>
    </div>
  );
}
